('7cdb797c-c093-4c47-9063-8f3aefb30786','Ög 200',NULL,58.336,15.2272,'§A …ʀ- --- …umla ufti (k)iʀ(m)(i) · þ(k)(n) · …u(t)(a)n b… … §B kuþm… …','§A … … [k]umla eptir "Geirma, þegn [n]ýtan, b[ónda](?) … §B "Guðm[undr(?)] …',NULL,'§A … to place a monument in memory of Geirmi, a capable thegn, husbandman(?) … §B Guðmundr(?) …',NULL,'J. P. Strid läste 1984 mut- kuml a(u)fti i mittenraden (ATA Dnr 4991/84). Inskriften §B finns på stenens högra smalsida. Nordén läser: kar-i--(u)-(i)(R) --------(R) --(þ)ka- utinkarl auk kirmutr kuml aufti... ... kuþm... ...','Runsten','Sten','Östergötland','Sweden'),
('abaad6b3-8c6d-4bd4-8520-ddc547a771b5','Ög 51','L 1660|B 921',58.3466,14.7104,'[barkuiþʀ : karþi : stin : þena] … (u)fiʀ : (u)…[hriþ : koþ : hialbi : sihol : hans :]','"Bergviðr/"Barkviðr gerði stein þenna yfir "…røð. "Guð hjalpi sál hans.','Bergvid/Barkvid gjorde denna sten över …-röd. Gud hjälpe hans ande.','Bergviðr/Barkviðr made this stone over …-røðr. May God help his soul.',NULL,'Ett fragment bevarat, det hade tidigare signum Ög N294. Under B 921 beskrivs även Ög 52, Ög 53.','Gravhäll','Grå kalksten','Östergötland','Sweden'),
('c218c76a-efb4-42cf-bf45-944fbbea6e8e','Ög 236',NULL,58.5825,16.4757,'× ufagʀ · raisþi · stain · þansa · eftiʀ · aystain · sun sin ×','"Ofagʀ ræisþi stæin þennsa æftiʀ "Øystæin, sun sinn.',NULL,'Ófeigr raised this stone in memory of Eysteinn, his son.',NULL,NULL,'Runsten','Grå granit med rödaktiga inslag','Östergötland','Sweden')
) as v(id, signum, alt, lat, lng, translit, norm, tsv, ten, dating, notes, otype, material, landscape, country)
